}

function maxDayForMonthField(Field memory month) private pure returns (uint8) {
  // DEV: ranges are always safe because any two consecutive months will always
  // contain a month with 31 days
  if (month.fieldType == FieldType.WILD || month.fieldType == FieldType.RANGE) {
    return 31;
  } else if (month.fieldType == FieldType.EXACT) {
    // DEV: assume leap year in order to get max value
    return DateTime.getDaysInMonth(month.singleValue, 4);
  } else if (month.fieldType == FieldType.INTERVAL) {
    if (month.interval == 9 || month.interval == 11) {
      return 30;
    } else {
      return 31;
    }
  } else if (month.fieldType == FieldType.LIST) {
    uint8 result;
    for (uint256 idx = 0; idx < month.listLength; idx++) {
      // DEV: assume leap year in order to get max value
      uint8 daysInMonth = DateTime.getDaysInMonth(month.list[idx], 4);
      if (daysInMonth == 31) {
        return daysInMonth;
      }
      if (daysInMonth > result) {
        result = daysInMonth;
      }
    }
    return result;
  } else {
    revert UnknownFieldType();
  }
}

function getUnderfundedAddresses() public view returns (address[] memory) {
  address[] memory watchList = s_watchList;
  address[] memory needsFunding = new address[](watchList.length);
  uint256 count = 0;
  uint256 minWaitPeriodSeconds = s_minWaitPeriodSeconds;
  uint256 contractBalance = s_erc20Token.balanceOf(address(this));
  Target memory target;
  for (uint256 idx = 0; idx < watchList.length; idx++) {
    target = s_targets[watchList[idx]];
    uint256 targetTokenBalance = s_erc20Token.balanceOf(watchList[idx]);
    if (
      target.lastTopUpTimestamp + minWaitPeriodSeconds <= block.timestamp &&
      targetTokenBalance < target.minBalance &&
      contractBalance >= (target.topUpLevel - targetTokenBalance)
    ) {
      uint256 topUpAmount = target.topUpLevel - targetTokenBalance;
      needsFunding[count] = watchList[idx];
      count++;
      contractBalance -= topUpAmount;
    }
  }
  if (count != watchList.length) {
    assembly {
      mstore(needsFunding, count) // resize array to number of valid targets
    }
  }
  return needsFunding;
}

function _burnBatch(
    address account,
    uint256[] memory ids,
    uint256[] memory amounts
) internal virtual {
    if (account == address(0)) revert MultiToken__BurnFromZeroAddress();
    if (ids.length != amounts.length)
        revert MultiToken__ArrayLengthMismatch();

    _beforeTokenTransfer(
        _msgSender(),
        account,
        address(0),
        ids,
        amounts,
        ''
    );

    mapping(uint256 tokenId => mapping(address account => uint256 balance))
        storage balances = ERC1155Storage
            .ref(ERC1155Storage.DEFAULT_STORAGE_SLOT)
            .balances;

    unchecked {
        for (uint256 i; i < ids.length; i++) {
            uint256 id = ids[i];
            if (amounts[i] > balances[id][account])
                revert MultiToken__BurnExceedsBalance();
            balances[id][account] -= amounts[i];
        }
    }

    emit TransferBatch(_msgSender(), account, address(0), ids, amounts);
}

function _transfer(
    address operator,
    address sender,
    address recipient,
    uint256 id,
    uint256 amount,
    bytes memory data
) internal virtual {
    if (recipient == address(0)) revert MultiToken__TransferToZeroAddress();

    _beforeTokenTransfer(
        operator,
        sender,
        recipient,
        _asSingletonArray(id),
        _asSingletonArray(amount),
        data
    );

    mapping(uint256 tokenId => mapping(address account => uint256 balance))
        storage balances = ERC1155Storage
            .ref(ERC1155Storage.DEFAULT_STORAGE_SLOT)
            .balances;

    unchecked {
        uint256 senderBalance = balances[id][sender];
        if (amount > senderBalance)
            revert MultiToken__TransferExceedsBalance();
        balances[id][sender] = senderBalance - amount;
    }

    balances[id][recipient] += amount;

    emit TransferSingle(operator, sender, recipient, id, amount);
}

function _mint(address to, uint256 quantity) internal {
    uint256 startTokenId = _currentIndex;
    if (to == address(0)) revert MintToZeroAddress();
    if (quantity == 0) revert MintZeroQuantity();

    _beforeTokenTransfers(address(0), to, startTokenId, quantity);

    // Overflows are incredibly unrealistic.
    // balance or numberMinted overflow if current value of either + quantity > 1.8e19 (2**64) - 1
    // updatedIndex overflows if _currentIndex + quantity > 1.2e77 (2**256) - 1
    unchecked {
        _addressData[to].balance += uint64(quantity);
        _addressData[to].numberMinted += uint64(quantity);

        _ownerships[startTokenId].addr = to;
        _ownerships[startTokenId].startTimestamp = uint64(block.timestamp);

        uint256 updatedIndex = startTokenId;
        uint256 end = updatedIndex + quantity;

        do {
            emit Transfer(address(0), to, updatedIndex++);
        } while (updatedIndex < end);

        _currentIndex = updatedIndex;
    }
    _afterTokenTransfers(address(0), to, startTokenId, quantity);
}

function getAllFunctionsOfPlugin(address _pluginAddress) external view returns (bytes4[] memory registered) {
    RouterStorage.Data storage data = RouterStorage.routerStorage();

    EnumerableSet.Bytes32Set storage selectorsForPlugin = data.selectorsForPlugin[_pluginAddress];
    bytes4[] memory defaultSelectors = IPluginMap(pluginMap).getAllFunctionsOfPlugin(_pluginAddress);

    uint256 len = defaultSelectors.length;
    uint256 count = selectorsForPlugin.length() + defaultSelectors.length;

    for (uint256 i = 0; i < len; i += 1) {
        if (selectorsForPlugin.contains(defaultSelectors[i])) {
            count -= 1;
            defaultSelectors[i] = bytes4(0);
        }
    }

    registered = new bytes4[](count);
    uint256 index;

    for (uint256 i = 0; i < len; i += 1) {
        if (defaultSelectors[i] != bytes4(0)) {
            registered[index++] = defaultSelectors[i];
        }
    }

    len = selectorsForPlugin.length();
    for (uint256 i = 0; i < len; i += 1) {
        registered[index++] = bytes4(data.selectorsForPlugin[_pluginAddress].at(i));
    }
}

