function beforeAllHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode _mode,
    bytes calldata,
    bytes32,
    address,
    address
)
    public
    override
    onlyDefaultExecutionMode(_mode)
{
    (address token_, address recipient_, uint256 amount_) = getTermsInfo(_terms);
    require(amount_ > 0, "ERC20MultiOperationIncreaseBalanceEnforcer:zero-expected-change-amount");

    bytes32 hashKey_ = _getHashKey(msg.sender, token_, recipient_);
    BalanceTracker memory balanceTracker_ = balanceTracker[hashKey_];

    uint256 currentBalance_ = IERC20(token_).balanceOf(recipient_);
    if (balanceTracker_.expectedIncrease == 0) {
        balanceTracker_.balanceBefore = currentBalance_;
        emit TrackedBalance(msg.sender, recipient_, token_, currentBalance_);
    }

    balanceTracker_.expectedIncrease += amount_;
    balanceTracker_.validationRemaining++;

    balanceTracker[hashKey_] = balanceTracker_;

    emit UpdatedExpectedBalance(msg.sender, recipient_, token_, amount_);
}

constructor(
    int256 baseRatePerYear_,
    int256 multiplierPerYear_,
    int256 kink1_,
    int256 multiplier2PerYear_,
    int256 baseRate2PerYear_,
    int256 kink2_,
    int256 jumpMultiplierPerYear_,
    int256 blocksPerYear_
) {
    if (baseRatePerYear_ < 0 || baseRate2PerYear_ < 0) {
        revert NegativeValueNotAllowed();
    }

    if (kink2_ <= kink1_ || kink1_ <= 0) {
        revert InvalidKink();
    }

    BLOCKS_PER_YEAR = blocksPerYear_;
    BASE_RATE_PER_BLOCK = baseRatePerYear_ / BLOCKS_PER_YEAR;
    MULTIPLIER_PER_BLOCK = multiplierPerYear_ / BLOCKS_PER_YEAR;
    KINK_1 = kink1_;
    MULTIPLIER_2_PER_BLOCK = multiplier2PerYear_ / BLOCKS_PER_YEAR;
    BASE_RATE_2_PER_BLOCK = baseRate2PerYear_ / BLOCKS_PER_YEAR;
    KINK_2 = kink2_;
    JUMP_MULTIPLIER_PER_BLOCK = jumpMultiplierPerYear_ / BLOCKS_PER_YEAR;

    int256 expScale = int256(EXP_SCALE);
    RATE_1 = (((KINK_1 * MULTIPLIER_PER_BLOCK) / expScale) + BASE_RATE_PER_BLOCK);

    int256 slope2Util;
    unchecked {
        slope2Util = KINK_2 - KINK_1;
    }
    RATE_2 = ((slope2Util * MULTIPLIER_2_PER_BLOCK) / expScale) + BASE_RATE_2_PER_BLOCK;
}

function _pAdd(
    PPoint memory pPoint1_,
    PPoint memory pPoint2_,
    uint256 p_,
    uint256 a_,
    uint256 d_
) private pure returns (PPoint memory pPoint3_) {
    assembly ("memory-safe") {
        let A_ := mulmod(mload(add(pPoint1_, 0x40)), mload(add(pPoint2_, 0x40)), p_)
        let B_ := mulmod(A_, A_, p_)
        let C_ := mulmod(mload(pPoint1_), mload(pPoint2_), p_)
        let D_ := mulmod(mload(add(pPoint1_, 0x20)), mload(add(pPoint2_, 0x20)), p_)
        let E_ := mulmod(d_, mulmod(C_, D_, p_), p_)
        let F_ := addmod(B_, sub(p_, E_), p_)
        B_ := addmod(B_, E_, p_)
        let H_ := mulmod(
            addmod(mload(pPoint1_), mload(add(pPoint1_, 0x20)), p_),
            addmod(mload(pPoint2_), mload(add(pPoint2_, 0x20)), p_),
            p_
        )
        H_ := addmod(addmod(H_, sub(p_, C_), p_), sub(p_, D_), p_)
        C_ := addmod(D_, sub(p_, mulmod(a_, C_, p_)), p_)

        mstore(pPoint3_, mulmod(F_, mulmod(A_, H_, p_), p_))
        mstore(add(pPoint3_, 0x20), mulmod(B_, mulmod(A_, C_, p_), p_))
        mstore(add(pPoint3_, 0x40), mulmod(F_, B_, p_))
    }
}

function backAndForthTraverseUint()
        external
        view
        returns (uint256[] memory, uint256[] memory)
    {
        Traversal.Iterator memory iterator_ = _uintTree.first();

        uint256[] memory keys_ = new uint256[](12);
        uint256[] memory values_ = new uint256[](12);

        bool[12] memory directions_ = [
            true,
            true,
            false,
            true,
            false,
            false,
            true,
            true,
            true,
            true,
            true,
            true
        ];

        bytes32 bytesKey_;
        bytes32 bytesValue_;

        for (uint256 i = 0; i < 12; ++i) {
            (bytesKey_, bytesValue_) = iterator_.value();

            keys_[i] = uint256(bytesKey_);
            values_[i] = uint256(bytesValue_);

            directions_[i] ? iterator_.next() : iterator_.prev();
        }

        return (keys_, values_);
    }

function splitTextToFit(string memory text) internal pure returns (string memory, string memory) {
    uint256 length1 = getFittingLength(text, MAX_WIDTH - 21); // 21px is @ width
    bytes memory text1Bytes = new bytes(length1);
    for (uint i = 0; i < length1; i++) {
        text1Bytes[i] = bytes(text)[i];
    }
    string memory text1 = string.concat('@', string(text1Bytes));

    uint256 length2 = bytes(text).length - length1;
    bytes memory text2Bytes = new bytes(length2);
    for (uint i = 0; i < length2; i++) {
        text2Bytes[i] = bytes(text)[length1 + i];
    }
    string memory text2 = string(text2Bytes);

    if (getTextWidth(text2) <= MAX_WIDTH) {
        return (text1, text2);
    } else {
        uint256 length3 = getFittingLength(text2, MAX_WIDTH - 18); // 18px is ... width
        bytes memory text3Bytes = new bytes(length3);
        for (uint i = 0; i < length3; i++) {
            text3Bytes[i] = bytes(text2)[i];
        }
        string memory text3 = string.concat(string(text3Bytes), '...');

        return (text1, text3);
    }
}
